import { useState } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({
    clinic_id: '',
    patient_name: '',
    phone: '',
    channel: 'whatsapp',
    service_type: '',
    description: '',
    criticality: 'media',
    status: 'aberta',
    attachment_url: '',
    notes: ''
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const salvar = async () => {
    try {
      await axios.post('http://localhost:3001/complaints', form);
      alert('Reclamação salva com sucesso!');
    } catch (err) {
      alert('Erro ao salvar');
    }
  };

  return (
    <div style={{ maxWidth: 600, margin: '40px auto', fontFamily: 'Arial' }}>
      <h2>Cadastro de Reclamação</h2>

      <input name="clinic_id" placeholder="ID da Clínica" onChange={handleChange} /><br/><br/>
      <input name="patient_name" placeholder="Nome do paciente" onChange={handleChange} /><br/><br/>
      <input name="phone" placeholder="Telefone" onChange={handleChange} /><br/><br/>

      <select name="channel" onChange={handleChange}>
        <option value="whatsapp">WhatsApp</option>
        <option value="email">Email</option>
        <option value="google">Google</option>
        <option value="reclame_aqui">Reclame Aqui</option>
        <option value="instagram">Instagram</option>
      </select><br/><br/>

      <input name="service_type" placeholder="Tipo de serviço" onChange={handleChange} /><br/><br/>

      <select name="criticality" onChange={handleChange}>
        <option value="baixa">Baixa</option>
        <option value="media">Média</option>
        <option value="alta">Alta</option>
        <option value="critica">Crítica</option>
      </select><br/><br/>

      <textarea name="description" placeholder="Descrição" onChange={handleChange}></textarea><br/><br/>

      <input name="attachment_url" placeholder="Link da evidência" onChange={handleChange} /><br/><br/>

      <textarea name="notes" placeholder="Observações internas"></textarea><br/><br/>

      <button onClick={salvar}>Salvar</button>
    </div>
  );
}

export default App;
